#include <iostream>
#include <sys/types.h>
#include <unistd.h>
#include <sys/wait.h>
#include <fcntl.h>

int main() {
    int fd[2];
    pipe(fd); // Crée un pipe

    pid_t pid = fork(); // Crée un nouveau processus

    if (pid == -1) {
        std::cerr << "Erreur dans fork()" << std::endl;
        return 1;
    } else if (pid == 0) {
        // C'est le processus fils
        close(fd[1]); // Ferme l'écriture
        dup2(fd[0], STDIN_FILENO); // Redirige l'entrée vers le pipe
        close(fd[0]); // Ferme le tube non nécessaire
        execlp("ls", "ls", "-l", (char *)0); // Exécute le programme
        std::cerr << "Erreur dans execlp()" << std::endl;
        return 1;
    } else {
        // C'est le processus père
        close(fd[0]); // Ferme la lecture
        dup2(fd[1], STDOUT_FILENO); // Redirige la sortie vers le pipe
        close(fd[1]); // Ferme le tube non nécessaire
        std::cout << "Sortie du processus père : " << std::endl;
        wait(NULL); // Attend que le processus fils termine
    }

    return 0;
}
